sql:
SELECT SUM(budget) AS total_budget
FROM crime_resources
WHERE city_id = 0;

SELECT SUM(murder + forcible_rape + robbery + aggravated_assault) AS total_violent_crimes
FROM violent_crimes
WHERE city_id = 1;

SELECT (burglary + larceny_theft + motor_vehicle_theft + arson) AS total_property_crimes
FROM property_crimes
WHERE city_id = 1;

SELECT resource_name, budget
FROM crime_resources
WHERE city_id = 1;

SELECT city_id
FROM crime_statistics
WHERE total_violent = (SELECT MAX(total_violent) FROM crime_statistics);

external_knowledge:
- 'Resolution duration' refers to the time taken to resolve a crime incident, calculated as the difference between the resolution time and the response time; 
- 'Response time variability' refers to the number of distinct ranks assigned to response times for a given crime type in a city, with the fastest response time ranked first; 
- 'Closed cases' are incidents with a status of 'Closed' in the officer logs; 
- 'Multiple reports' refers to crime types with more than one report in a city.

